<?php
 namespace WPAICG\ContentWriter\Ajax\Actions\GenerateTitle; use WPAICG\ContentWriter\Ajax\Actions\AIPKit_Content_Writer_Generate_Title_Action; use WP_Error; if (!defined('ABSPATH')) { exit; } function call_title_generator_logic( AIPKit_Content_Writer_Generate_Title_Action $handler, string $provider, string $model, array $messages, array $ai_params_override, string $system_instruction, array $form_data = [] ): array|WP_Error { $user_message = $messages[0]['content'] ?? ''; [$system_instruction, $ai_params_override, $instruction_context] = $handler->prepare_content_writer_vector_context( $user_message, $provider, $system_instruction, $ai_params_override, $form_data ); return $handler->get_ai_caller()->make_standard_call( $provider, $model, $messages, $ai_params_override, $system_instruction, $instruction_context ); } 